,p_lov_name=>'LOV_EXP_FILES'
,p_lov_query=>wwv_flow_string.join(wwv_flow_t_varchar2(
'select distinct mr.filename label, mr.filename id from marl_results mr, EXPERIMENT e, EXPERIMENT_FILES ef',
'WHERE e.id=ef.experiment_id and mr.filename=ef.filename and e.id=:P8_SELECT_EXPERIMENT',
