wwv_flow_imp_page.create_jet_chart_series(
 p_id=>wwv_flow_imp.id(122199514205622848)
,p_chart_id=>wwv_flow_imp.id(122199486950622847)
,p_seq=>10
,p_name=>'New'
,p_data_source_type=>'SQL'
,p_data_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'    comm_mode,',
'    episode,',
'    goals_reached_this_ep                                      AS raw_goals,',
'    ROUND(',
'        AVG(goals_reached_this_ep) OVER (',
'            PARTITION BY comm_mode',
'            ORDER BY episode',
'            ROWS BETWEEN 19 PRECEDING AND CURRENT ROW',
'        ), 4)                                                   AS rolling_mean_20,',
'    ROUND(',
'        AVG(goals_reached_this_ep) OVER (',
'            PARTITION BY comm_mode',
'            ORDER BY episode',
'            ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW',
'        ), 4)                                                   AS cumulative_mean',
'FROM marl_results mr, EXPERIMENT e, EXPERIMENT_FILES ef',
'WHERE e.id=ef.experiment_id and mr.filename=ef.filename and e.id=:P6_SELECT_EXPERIMENT',
'  and goal_mode      = :P6_MODE',
'  AND mode_exec      = ''train''',
'ORDER BY comm_mode, episode'))
,p_ajax_items_to_submit=>'P6_SELECT_EXPERIMENT,P6_MODE'
,p_series_name_column_name=>'COMM_MODE'
,p_items_value_column_name=>'CUMULATIVE_MEAN'
,p_group_name_column_name=>'COMM_MODE'
,p_items_label_column_name=>'EPISODE'
,p_line_style=>'solid'
,p_line_type=>'auto'
,p_marker_rendered=>'auto'
,p_marker_shape=>'auto'
,p_assigned_to_y2=>'off'
,p_items_label_rendered=>false
);
