wwv_flow_imp_page.create_jet_chart_series(
 p_id=>wwv_flow_imp.id(125204946440038504)
,p_chart_id=>wwv_flow_imp.id(125204858499038503)
,p_seq=>10
,p_name=>'New'
,p_data_source_type=>'SQL'
,p_data_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'    comm_mode,',
'    episode,',
'    -- Raw values',
'    holes                                                           AS deaths_this_ep,',
'    ROUND(',
'        (a0_in_hole + a1_in_hole + a2_in_hole + a3_in_hole)',
'        / 4.0 * 100',
'    , 2)                                                            AS hole_pct_per_agent_raw,',
'    -- Rolling death rate (avg holes per episode)',
'    ROUND(',
'        AVG(holes) OVER (',
'            PARTITION BY comm_mode',
'            ORDER BY episode',
'            ROWS BETWEEN 19 PRECEDING AND CURRENT ROW',
'        ), 4)                                                       AS rolling_death_rate,',
'    -- Rolling hole % per agent',
'    ROUND(',
'        AVG(',
'            (a0_in_hole + a1_in_hole + a2_in_hole + a3_in_hole)',
'            / 4.0 * 100',
'        ) OVER (',
'            PARTITION BY comm_mode',
'            ORDER BY episode',
'            ROWS BETWEEN 19 PRECEDING AND CURRENT ROW',
'        ), 2)                                                       AS rolling_hole_pct_per_agent,',
'    -- Cumulative hole % per agent',
'    ROUND(',
'        AVG(',
'            (a0_in_hole + a1_in_hole + a2_in_hole + a3_in_hole)',
'            / 4.0 * 100',
'        ) OVER (',
'            PARTITION BY comm_mode',
'            ORDER BY episode',
'            ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW',
'        ), 2)                                                       AS cumulative_hole_pct',
'FROM marl_results mr, experiment e, experiment_files ef',
'WHERE e.id          = ef.experiment_id',
'  AND mr.filename   = ef.filename',
'  AND e.id          = :P6_SELECT_EXPERIMENT',
'  AND goal_mode     = :P6_MODE',
'  AND mode_exec     = ''train''',
'ORDER BY comm_mode, episode'))
,p_ajax_items_to_submit=>'P6_SELECT_EXPERIMENT,P6_MODE'
,p_series_name_column_name=>'COMM_MODE'
,p_items_value_column_name=>'ROLLING_DEATH_RATE'
,p_group_name_column_name=>'COMM_MODE'
,p_items_label_column_name=>'EPISODE'
,p_line_style=>'solid'
,p_line_type=>'auto'
