wwv_flow_imp_page.create_jet_chart_series(
 p_id=>wwv_flow_imp.id(125205701879038512)
,p_chart_id=>wwv_flow_imp.id(125205600188038511)
,p_seq=>10
,p_name=>'New'
,p_data_source_type=>'SQL'
,p_data_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'    comm_mode,',
'    episode,',
'    -- Best (minimum) steps among winning agents this episode',
'    LEAST(',
'        NVL(CASE WHEN a0_win = 1 AND a0_steps_to_goal > 0',
'                 THEN a0_steps_to_goal END, 9999),',
'        NVL(CASE WHEN a1_win = 1 AND a1_steps_to_goal > 0',
'                 THEN a1_steps_to_goal END, 9999),',
'        NVL(CASE WHEN a2_win = 1 AND a2_steps_to_goal > 0',
'                 THEN a2_steps_to_goal END, 9999),',
'        NVL(CASE WHEN a3_win = 1 AND a3_steps_to_goal > 0',
'                 THEN a3_steps_to_goal END, 9999)',
'    )                                                               AS best_steps_this_ep,',
'    -- Average steps across all winning agents this episode',
'    ROUND(',
'        (   NVL(CASE WHEN a0_win = 1 AND a0_steps_to_goal > 0',
'                     THEN a0_steps_to_goal END, NULL) +',
'            NVL(CASE WHEN a1_win = 1 AND a1_steps_to_goal > 0',
'                     THEN a1_steps_to_goal END, NULL) +',
'            NVL(CASE WHEN a2_win = 1 AND a2_steps_to_goal > 0',
'                     THEN a2_steps_to_goal END, NULL) +',
'            NVL(CASE WHEN a3_win = 1 AND a3_steps_to_goal > 0',
'                     THEN a3_steps_to_goal END, NULL)',
'        ) /',
'        NULLIF(',
'            NVL2(CASE WHEN a0_win=1 AND a0_steps_to_goal>0',
'                      THEN 1 END, 1, 0) +',
'            NVL2(CASE WHEN a1_win=1 AND a1_steps_to_goal>0',
'                      THEN 1 END, 1, 0) +',
'            NVL2(CASE WHEN a2_win=1 AND a2_steps_to_goal>0',
'                      THEN 1 END, 1, 0) +',
'            NVL2(CASE WHEN a3_win=1 AND a3_steps_to_goal>0',
'                      THEN 1 END, 1, 0)',
'        , 0)',
'    , 1)                                                            AS avg_steps_winners_raw,',
'    -- Rolling average steps to goal (W=20, only winning episodes)',
'    ROUND(',
'        AVG(',
'            CASE WHEN (a0_win + a1_win + a2_win + a3_win) > 0',
'            THEN (',
'                NVL(CASE WHEN a0_win=1 AND a0_steps_to_goal>0',
'                         THEN a0_steps_to_goal END, 0) +',
'                NVL(CASE WHEN a1_win=1 AND a1_steps_to_goal>0',
'                         THEN a1_steps_to_goal END, 0) +',
'                NVL(CASE WHEN a2_win=1 AND a2_steps_to_goal>0',
'                         THEN a2_steps_to_goal END, 0) +',
'                NVL(CASE WHEN a3_win=1 AND a3_steps_to_goal>0',
'                         THEN a3_steps_to_goal END, 0)',
'            ) /',
'            NULLIF(a0_win + a1_win + a2_win + a3_win, 0)',
'            END',
'        ) OVER (',
'            PARTITION BY comm_mode',
'            ORDER BY episode',
'            ROWS BETWEEN 19 PRECEDING AND CURRENT ROW',
'        ), 1)                                                       AS rolling_avg_steps,',
'    -- Cumulative average steps to goal',
'    ROUND(',
'        AVG(',
'            CASE WHEN (a0_win + a1_win + a2_win + a3_win) > 0',
'            THEN (',
'                NVL(CASE WHEN a0_win=1 AND a0_steps_to_goal>0',
'                         THEN a0_steps_to_goal END, 0) +',
'                NVL(CASE WHEN a1_win=1 AND a1_steps_to_goal>0',
'                         THEN a1_steps_to_goal END, 0) +',
'                NVL(CASE WHEN a2_win=1 AND a2_steps_to_goal>0',
'                         THEN a2_steps_to_goal END, 0) +',
'                NVL(CASE WHEN a3_win=1 AND a3_steps_to_goal>0',
'                         THEN a3_steps_to_goal END, 0)',
'            ) /',
'            NULLIF(a0_win + a1_win + a2_win + a3_win, 0)',
'            END',
'        ) OVER (',
'            PARTITION BY comm_mode',
'            ORDER BY episode',
'            ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW',
'        ), 1)                                                       AS cumulative_avg_steps',
'FROM marl_results mr, experiment e, experiment_files ef',
'WHERE e.id          = ef.experiment_id',
'  AND mr.filename   = ef.filename',
'  AND e.id          = :P6_SELECT_EXPERIMENT',
'  AND goal_mode     = :P6_MODE',
'  AND mode_exec     = ''train''',
'ORDER BY comm_mode, episode'))
,p_ajax_items_to_submit=>'P6_SELECT_EXPERIMENT,P6_MODE'
,p_series_name_column_name=>'COMM_MODE'
,p_items_value_column_name=>'ROLLING_AVG_STEPS'
,p_group_name_column_name=>'COMM_MODE'
,p_items_label_column_name=>'EPISODE'
,p_line_style=>'solid'
,p_line_type=>'auto'
,p_marker_rendered=>'auto'
,p_marker_shape=>'auto'
,p_assigned_to_y2=>'off'
,p_items_label_rendered=>false
);
