wwv_flow_imp_page.create_jet_chart_series(
 p_id=>wwv_flow_imp.id(125206201260038517)
,p_chart_id=>wwv_flow_imp.id(125206174134038516)
,p_seq=>10
,p_name=>'New'
,p_data_source_type=>'SQL'
,p_data_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'    comm_mode,',
'    CASE',
'        WHEN episode <  166 THEN ''1_exploration''',
'        WHEN episode <  332 THEN ''2_transition''',
'        ELSE                     ''3_exploitation''',
'    END                                             AS phase,',
'    ROUND(AVG(goals_reached_this_ep), 3)            AS avg_goals,',
'    ROUND(STDDEV(goals_reached_this_ep), 3)         AS std_goals,',
'    ROUND(',
'        STDDEV(goals_reached_this_ep) /',
'        NULLIF(AVG(goals_reached_this_ep), 0)',
'    , 3)                                            AS coeff_variation,',
'    ROUND(AVG(holes), 3)                            AS avg_deaths',
'FROM marl_results mr, experiment e, experiment_files ef',
'WHERE e.id        = ef.experiment_id',
'  AND mr.filename = ef.filename',
'  AND e.id        = :P6_SELECT_EXPERIMENT',
'  AND mode_exec   = ''train''',
'  and goal_mode= :P6_MODE',
'GROUP BY',
'    comm_mode,',
'    CASE',
'        WHEN episode <  166 THEN ''1_exploration''',
'        WHEN episode <  332 THEN ''2_transition''',
'        ELSE                     ''3_exploitation''',
'    END',
'ORDER BY comm_mode, phase'))
,p_ajax_items_to_submit=>'P6_SELECT_EXPERIMENT,P6_MODE'
,p_series_name_column_name=>'COMM_MODE'
,p_items_value_column_name=>'COEFF_VARIATION'
,p_group_name_column_name=>'COMM_MODE'
,p_items_label_column_name=>'PHASE'
,p_line_style=>'solid'
,p_line_type=>'auto'
,p_marker_rendered=>'auto'
,p_marker_shape=>'auto'
,p_assigned_to_y2=>'off'
,p_items_label_rendered=>false
);
