,p_chart_id=>wwv_flow_imp.id(126285524376619706)
,p_seq=>10
,p_name=>'cumulative agent status'
,p_data_source_type=>'SQL'
,p_data_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT comm_mode, ''wins''      AS category,',
'    SUM(a0_win + a1_win + a2_win + a3_win)              AS value',
'FROM marl_results mr, experiment e, experiment_files ef',
'WHERE e.id = ef.experiment_id AND mr.filename = ef.filename',
'  AND e.id = :P7_SELECT_EXPERIMENT and goal_mode=:P7_MODE AND mode_exec = ''test''',
'    and COMM_RADIUS = :P7_RADIUS',
'GROUP BY comm_mode',
'',
'UNION ALL',
'',
'SELECT comm_mode, ''survivors'' AS category,',
'    SUM(GREATEST(',
'        agents_alive_end - (a0_win + a1_win + a2_win + a3_win), 0))',
'FROM marl_results mr, experiment e, experiment_files ef',
'WHERE e.id = ef.experiment_id AND mr.filename = ef.filename',
'  AND e.id = :P7_SELECT_EXPERIMENT and goal_mode=:P7_MODE AND mode_exec = ''test''',
'    and COMM_RADIUS = :P7_RADIUS',
'GROUP BY comm_mode',
'',
'UNION ALL',
'',
'SELECT comm_mode, ''deaths''    AS category,',
'    SUM(a0_in_hole + a1_in_hole + a2_in_hole + a3_in_hole)',
'FROM marl_results mr, experiment e, experiment_files ef',
'WHERE e.id = ef.experiment_id AND mr.filename = ef.filename',
'  AND e.id = :P7_SELECT_EXPERIMENT  and goal_mode=:P7_MODE AND mode_exec = ''test''',
'    and COMM_RADIUS = :P7_RADIUS',
'GROUP BY comm_mode',
'',
'ORDER BY comm_mode',
''))
,p_max_row_count=>20
,p_ajax_items_to_submit=>'P7_SELECT_EXPERIMENT,P7_MODE,P7_RADIUS'
,p_series_name_column_name=>'COMM_MODE'
,p_items_value_column_name=>'VALUE'
,p_items_label_column_name=>'CATEGORY'
