wwv_flow_imp_page.create_jet_chart_series(
 p_id=>wwv_flow_imp.id(126287085824619721)
,p_chart_id=>wwv_flow_imp.id(126286913866619720)
,p_seq=>10
,p_name=>'Outcome'
,p_data_source_type=>'SQL'
,p_data_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'    comm_mode,',
'    CASE',
'        WHEN goals_reached_this_ep  = 0 THEN ''00_not_reached''',
'        WHEN steps <=  30            THEN ''01_very_fast  (0-30)''',
'        WHEN steps <=  60            THEN ''02_fast       (31-60)''',
'        WHEN steps <=  90            THEN ''03_medium     (61-90)''',
'        WHEN steps <= 120            THEN ''04_slow       (91-120)''',
'        ELSE                              ''05_timeout    (121+)''',
'    END                                                 AS steps_bucket,',
'    COUNT(*)                                            AS n_episodes,',
'    ROUND(COUNT(*) * 100.0 /',
'        SUM(COUNT(*)) OVER (PARTITION BY comm_mode)',
'    , 1)                                                AS pct,',
'    ROUND(AVG(goals_reached_this_ep), 2)                AS avg_goals,',
'    ROUND(AVG(total_reward), 2)                         AS avg_reward,',
'    ROUND(AVG(holes), 2)                                AS avg_deaths',
'FROM marl_results mr, experiment e, experiment_files ef',
'WHERE e.id        = ef.experiment_id',
'  AND mr.filename = ef.filename',
'  AND e.id        = :P7_SELECT_EXPERIMENT',
'  AND goal_mode   = :P7_MODE',
'    and COMM_RADIUS = :P7_RADIUS',
'  AND mode_exec   = ''test''',
'GROUP BY',
'    comm_mode,',
'    CASE',
'        WHEN goals_reached_this_ep  = 0 THEN ''00_not_reached''',
'        WHEN steps <=  30            THEN ''01_very_fast  (0-30)''',
'        WHEN steps <=  60            THEN ''02_fast       (31-60)''',
'        WHEN steps <=  90            THEN ''03_medium     (61-90)''',
'        WHEN steps <= 120            THEN ''04_slow       (91-120)''',
'        ELSE                              ''05_timeout    (121+)''',
'    END',
'ORDER BY comm_mode, steps_bucket'))
,p_max_row_count=>1000
,p_ajax_items_to_submit=>'P7_MODE,P7_SELECT_EXPERIMENT,P7_RADIUS'
,p_series_name_column_name=>'COMM_MODE'
,p_items_value_column_name=>'PCT'
,p_items_label_column_name=>'STEPS_BUCKET'
,p_assigned_to_y2=>'off'
,p_items_label_rendered=>false
);
