wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(126288398946619734)
,p_plug_name=>'Reward analysis'
,p_parent_plug_id=>wwv_flow_imp.id(125209578950038550)
,p_region_template_options=>'#DEFAULT#:t-IRR-region--hideHeader js-addHiddenHeadingRoleDesc'
,p_component_template_options=>'#DEFAULT#'
,p_plug_template=>2100526641005906379
,p_plug_display_sequence=>70
,p_plug_new_grid_row=>false
,p_plug_display_point=>'SUB_REGIONS'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'    comm_mode,',
'    -- Episodes ending with full cooperative win',
'    ROUND(AVG(CASE WHEN goals_reached_this_ep = 4',
'              THEN total_reward END), 2)                AS avg_reward_full_win,',
'    -- Episodes with at least one goal',
'    ROUND(AVG(CASE WHEN goals_reached_this_ep > 0',
'              THEN total_reward END), 2)                AS avg_reward_with_any_goal,',
'    -- Episodes with zero goals but no deaths (pure timeout)',
'    ROUND(AVG(CASE WHEN goals_reached_this_ep = 0',
'                   AND holes = 0',
'              THEN total_reward END), 2)                AS avg_reward_timeout_without_goal_or_hole,',
'    -- Episodes with deaths',
'    ROUND(AVG(CASE WHEN holes > 0',
'              THEN total_reward END), 2)                AS avg_reward_with_deaths,',
'    -- All dead episodes',
'    ROUND(AVG(CASE WHEN outcome = ''all_dead''',
'              THEN total_reward END), 2)                AS avg_reward_all_dead,',
'    -- Overall',
'    ROUND(AVG(total_reward), 2)                         AS avg_reward_global',
'FROM marl_results mr, experiment e, experiment_files ef',
'WHERE e.id        = ef.experiment_id',
'  AND mr.filename = ef.filename',
'  AND e.id        = :P7_SELECT_EXPERIMENT',
'  AND mode_exec   = ''test''',
'  and goal_mode = :P7_MODE',
'    and COMM_RADIUS = :P7_RADIUS',
'GROUP BY comm_mode'))
,p_plug_source_type=>'NATIVE_IG'
,p_ajax_items_to_submit=>'P7_SELECT_EXPERIMENT,P7_MODE,P7_RADIUS'
