wwv_flow_imp_page.create_jet_chart_series(
 p_id=>wwv_flow_imp.id(126361898662261232)
,p_chart_id=>wwv_flow_imp.id(126361721871261231)
,p_seq=>10
,p_name=>'Outcome'
,p_data_source_type=>'SQL'
,p_data_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'    CASE',
'        WHEN goals_reached_this_ep  = 4 THEN ''3_full_win''',
'        WHEN goals_reached_this_ep  > 0 THEN ''2_partial_win''',
'        ELSE                                 ''1_not_reached''',
'    END                                                 AS series,',
'    comm_mode || '' | '' ||',
'    CASE',
'        WHEN steps <=  30 THEN ''01_very_fast  (0-30)''',
'        WHEN steps <=  60 THEN ''02_fast       (31-60)''',
'        WHEN steps <=  90 THEN ''03_medium     (61-90)''',
'        WHEN steps <= 120 THEN ''04_slow       (91-120)''',
'        ELSE                   ''05_timeout    (121+)''',
'    END                                                 AS label,',
'    ROUND(COUNT(*) * 100.0 /',
'        SUM(COUNT(*)) OVER (',
'            PARTITION BY comm_mode,',
'            CASE',
'                WHEN steps <=  30 THEN ''01_very_fast  (0-30)''',
'                WHEN steps <=  60 THEN ''02_fast       (31-60)''',
'                WHEN steps <=  90 THEN ''03_medium     (61-90)''',
'                WHEN steps <= 120 THEN ''04_slow       (91-120)''',
'                ELSE                   ''05_timeout    (121+)''',
'            END',
'        )',
'    , 1)                                                AS value',
'FROM marl_results mr, experiment e, experiment_files ef',
'WHERE e.id        = ef.experiment_id',
'  AND mr.filename = ef.filename',
'  AND e.id        = :P7_SELECT_EXPERIMENT',
'  AND goal_mode   = :P7_MODE',
'    and COMM_RADIUS = :P7_RADIUS',
'  AND mode_exec   = ''test''',
'GROUP BY',
'    CASE',
'        WHEN goals_reached_this_ep  = 4 THEN ''3_full_win''',
'        WHEN goals_reached_this_ep  > 0 THEN ''2_partial_win''',
'        ELSE                                 ''1_not_reached''',
'    END,',
'    comm_mode,',
'    CASE',
'        WHEN steps <=  30 THEN ''01_very_fast  (0-30)''',
'        WHEN steps <=  60 THEN ''02_fast       (31-60)''',
'        WHEN steps <=  90 THEN ''03_medium     (61-90)''',
'        WHEN steps <= 120 THEN ''04_slow       (91-120)''',
'        ELSE                   ''05_timeout    (121+)''',
'    END',
'ORDER BY label, series'))
,p_max_row_count=>1000
,p_ajax_items_to_submit=>'P7_MODE,P7_SELECT_EXPERIMENT,P7_RADIUS'
,p_series_name_column_name=>'SERIES'
,p_items_value_column_name=>'VALUE'
,p_items_label_column_name=>'LABEL'
,p_assigned_to_y2=>'off'
,p_items_label_rendered=>true
,p_items_label_position=>'auto'
);
