,p_name=>'Alive - reached goal'
,p_data_source_type=>'SQL'
,p_data_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'    TO_CHAR(episode, ''FM000'')                             AS label,',
'    goals_reached_this_ep                AS value,',
'    outcome                              AS tooltip_outcome,',
'    agents_alive_end                     AS tooltip_alive,',
'    agents_dead_end                      AS tooltip_dead',
'FROM marl_results',
'WHERE outcome LIKE ''goal%''',
'and filename=:P7_FILE',
'ORDER BY episode',
''))
,p_max_row_count=>500
,p_ajax_items_to_submit=>'P7_FILE'
