,p_chart_id=>wwv_flow_imp.id(126529717939745169)
,p_seq=>10
,p_name=>'cumulative agent status'
,p_data_source_type=>'SQL'
,p_data_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'    comm_mode                                           AS series,',
'    goal_mode                                           AS label,',
'    ROUND(',
'        AVG(',
'            a0_comm_received + a1_comm_received +',
'            a2_comm_received + a3_comm_received',
'        ) / 4.0                                         -- per agent average',
'    , 1)                                                AS value,',
'    -- Additional context columns (useful for tooltip)',
'    COUNT(*)                                            AS n_episodes,',
'    ROUND(AVG(goals_reached_this_ep), 2)                AS avg_goals,',
'    ROUND(AVG(',
'        a0_comm_received + a1_comm_received +',
'        a2_comm_received + a3_comm_received',
'    ), 1)                                               AS total_comm_per_ep',
'FROM marl_results mr, experiment e, experiment_files ef',
'WHERE e.id        = ef.experiment_id',
'  AND mr.filename = ef.filename',
'  AND e.id        = :P9_SELECT_EXPERIMENT',
'  AND mode_exec   = ''test''',
'  AND goal_mode   =:P9_GOAL_MODE',
'  AND COMM_RADIUS = :P9_RADIUS',
'GROUP BY comm_mode, goal_mode',
'ORDER BY',
unistr('    -- Goal mode order: fixed \2192 random \2192 moving (increasing difficulty)'),
'    CASE goal_mode',
'        WHEN ''fixed''  THEN 1',
'        WHEN ''random'' THEN 2',
'        WHEN ''moving'' THEN 3',
'    END,',
'    -- Comm mode order for consistent legend',
'    CASE comm_mode',
'        WHEN ''none''        THEN 1',
'        WHEN ''centralized'' THEN 2',
'        WHEN ''proximity''   THEN 3',
'        WHEN ''scout''       THEN 4',
'    END'))
