,p_seq=>10
,p_name=>'communication'
,p_data_source_type=>'SQL'
,p_data_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'    comm_mode                                           AS series,',
'    CASE goal_mode',
'        WHEN ''fixed''  THEN ''1_fixed''',
'        WHEN ''random'' THEN ''2_random''',
'        WHEN ''moving'' THEN ''3_moving''',
'    END                                                 AS label,',
'    -- Box plot requires exactly these 5 statistical values',
'    ROUND(MIN(',
'        a0_comm_received + a1_comm_received +',
'        a2_comm_received + a3_comm_received',
'    ), 1)                                               AS low,',
'    ROUND(PERCENTILE_CONT(0.25) WITHIN GROUP (',
'        ORDER BY',
'        a0_comm_received + a1_comm_received +',
'        a2_comm_received + a3_comm_received',
'    ), 1)                                               AS q1_sql,',
'    ROUND(PERCENTILE_CONT(0.50) WITHIN GROUP (',
'        ORDER BY',
'        a0_comm_received + a1_comm_received +',
'        a2_comm_received + a3_comm_received',
'    ), 1)                                               AS median_val,',
'    ROUND(PERCENTILE_CONT(0.75) WITHIN GROUP (',
'        ORDER BY',
'        a0_comm_received + a1_comm_received +',
'        a2_comm_received + a3_comm_received',
'    ), 1)                                               AS q3_sql,',
'    ROUND(MAX(',
'        a0_comm_received + a1_comm_received +',
'        a2_comm_received + a3_comm_received',
'    ), 1)                                               AS high',
'FROM marl_results mr, experiment e, experiment_files ef',
'WHERE e.id        = ef.experiment_id',
'  AND mr.filename = ef.filename',
'  AND e.id        = :P9_SELECT_EXPERIMENT',
'  AND mode_exec   = ''test''',
'  AND goal_mode   = :P9_GOAL_MODE',
'  AND COMM_RADIUS = :P9_RADIUS',
'GROUP BY comm_mode, goal_mode',
'ORDER BY',
'    CASE goal_mode',
'        WHEN ''fixed''  THEN 1',
'        WHEN ''random'' THEN 2',
'        WHEN ''moving'' THEN 3',
'    END,',
'    CASE comm_mode',
'        WHEN ''none''        THEN 1',
'        WHEN ''centralized'' THEN 2',
'        WHEN ''proximity''   THEN 3',
'        WHEN ''scout''       THEN 4',
'    END'))
,p_max_row_count=>1000
,p_ajax_items_to_submit=>'P9_GOAL_MODE,P9_SELECT_EXPERIMENT,P9_RADIUS'
