,p_legend_position=>'auto'
,p_javascript_code=>wwv_flow_string.join(wwv_flow_t_varchar2(
'function(options) {',
'    options.yAxis = {',
unistr('        title: ''goals(high comm) \2212 goals(low comm)'''),
'    };',
'    options.xAxis = {',
unistr('        title: ''Goal mode (increasing difficulty \2192)'''),
'    };',
'    // Reference line at zero',
'    options.plotArea = {',
'        referenceObjects: [{',
'            type: ''line'',',
'            value: 0,',
'            color: ''#888780'',',
'            lineStyle: ''dashed'',',
'            lineWidth: 1',
'        }]',
'    };',
'',
'    options.dataLabelStyle = {',
'        position: ''outsideBarEdge''',
'    };',
'',
'',
'',
'    ',
'    if (!options.styleDefaults) options.styleDefaults = {};',
'        options.styleDefaults.dataLabelStyle = ''auto'';',
'',
'',
'    // Override the value formatter via xAxis valueFormats',
'    if (!options.valueFormats) options.valueFormats = {};',
'    options.valueFormats.value = {',
'        converter: {',
'            format: function(v) {',
'                if (v === null || isNaN(v)) return '''';',
'                var sign = v >= 0 ? ''+'' : '''';',
'                return sign + parseFloat(v).toFixed(3);',
'            }',
'        }',
'    };',
'',
'',
unistr('        // Step 1 \2014 enable labels on every series'),
'    if (options.series) {',
'        options.series.forEach(function(s) {',
'            s.dataLabelPosition = ''outsideBarEdge'';',
'        });',
'    }',
'',
unistr('    // Step 2 \2014 format the label value'),
'    options.dataLabel = function(dataContext) {',
'        var v = dataContext.value;',
'        if (v === null || v === undefined || isNaN(v)) return '''';',
'        var sign = v >= 0 ? ''+'' : '''';',
'        return sign + parseFloat(v).toFixed(3);',
'    };',
'    ',
'    return options;',
'}',
''))
);
wwv_flow_imp_page.create_jet_chart_series(
 p_id=>wwv_flow_imp.id(126518902603745115)
,p_chart_id=>wwv_flow_imp.id(126517206083745109)
,p_seq=>10
,p_name=>'Outcome'
,p_data_source_type=>'SQL'
,p_data_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'WITH base AS (',
'    SELECT',
'        comm_mode,',
'        goal_mode,',
'        goals_reached_this_ep,',
'        (a0_comm_received + a1_comm_received +',
'         a2_comm_received + a3_comm_received)           AS total_comm',
'    FROM marl_results mr, experiment e, experiment_files ef',
'    WHERE e.id        = ef.experiment_id',
'      AND mr.filename = ef.filename',
'      AND e.id        = :P9_SELECT_EXPERIMENT',
'            AND COMM_RADIUS = :P9_RADIUS',
'      AND mode_exec   = ''test''',
'),',
'percentiles AS (',
'    SELECT',
'        comm_mode,',
'        goal_mode,',
'        PERCENTILE_CONT(0.33) WITHIN GROUP',
'            (ORDER BY total_comm)                       AS p33,',
'        PERCENTILE_CONT(0.66) WITHIN GROUP',
'            (ORDER BY total_comm)                       AS p66',
'    FROM base',
'    GROUP BY comm_mode, goal_mode',
'),',
'bucketed AS (',
'    SELECT',
'        b.comm_mode,',
'        b.goal_mode,',
'        b.goals_reached_this_ep,',
'        b.total_comm,',
'        CASE',
'            WHEN b.total_comm <= p.p33 THEN ''1_low''',
'            WHEN b.total_comm <= p.p66 THEN ''2_med''',
'            ELSE                            ''3_high''',
'        END                                             AS comm_bucket',
'    FROM base b',
'    JOIN percentiles p',
'      ON b.comm_mode = p.comm_mode',
'     AND b.goal_mode = p.goal_mode',
'),',
'bucket_goals AS (',
'    SELECT',
'        comm_mode,',
'        goal_mode,',
'        comm_bucket,',
'        ROUND(AVG(goals_reached_this_ep), 4)            AS avg_goals',
'    FROM bucketed',
'    GROUP BY comm_mode, goal_mode, comm_bucket',
'),',
'slopes AS (',
'    SELECT',
'        comm_mode,',
'        goal_mode,',
'        -- Goals in high comm episodes',
'        MAX(CASE WHEN comm_bucket = ''3_high''',
'                 THEN avg_goals END)                    AS goals_high_comm,',
'        -- Goals in low comm episodes',
'        MAX(CASE WHEN comm_bucket = ''1_low''',
'                 THEN avg_goals END)                    AS goals_low_comm,',
'        -- Slope = improvement from low to high comm',
'        MAX(CASE WHEN comm_bucket = ''3_high''',
'                 THEN avg_goals END) -',
'        MAX(CASE WHEN comm_bucket = ''1_low''',
'                 THEN avg_goals END)                    AS comm_benefit_slope',
'    FROM bucket_goals',
'    GROUP BY comm_mode, goal_mode',
')',
'-- Final output for APEX bar chart',
'SELECT',
'    comm_mode                                           AS series,',
'    CASE goal_mode',
'        WHEN ''fixed''  THEN ''1_fixed''',
'        WHEN ''random'' THEN ''2_random''',
'        WHEN ''moving'' THEN ''3_moving''',
'    END                                                 AS label,',
'    ROUND(comm_benefit_slope, 3)                        AS value,',
'    ROUND(goals_high_comm, 3)                           AS goals_high_comm,',
'    ROUND(goals_low_comm, 3)                            AS goals_low_comm',
'FROM slopes',
'ORDER BY',
'    CASE goal_mode',
'        WHEN ''fixed''  THEN 1',
'        WHEN ''random'' THEN 2',
'        WHEN ''moving'' THEN 3',
'    END,',
'    CASE comm_mode',
'        WHEN ''none''        THEN 1',
'        WHEN ''centralized'' THEN 2',
'        WHEN ''proximity''   THEN 3',
'        WHEN ''scout''       THEN 4',
'    END'))
,p_max_row_count=>1000
,p_ajax_items_to_submit=>'P9_GOAL_MODE,P9_SELECT_EXPERIMENT,P9_RADIUS'
,p_series_name_column_name=>'SERIES'
,p_items_value_column_name=>'VALUE'
,p_items_label_column_name=>'LABEL'
,p_assigned_to_y2=>'off'
,p_items_label_rendered=>true
,p_items_label_position=>'outsideBarEdge'
);
