'function(options) {',
'       // Fix radar axis scale',
'    options.yAxis = {',
'        min: 0,',
'        max: 100',
'    };',
'    options.dataFilter = function(data) {',
'        // Sort series so _comm (dashed rings) render last = on top',
'        data.series.sort(function(a, b) {',
'            var aIsComm = a.name.endsWith(''_comm'') ? 1 : 0;',
'            var bIsComm = b.name.endsWith(''_comm'') ? 1 : 0;',
'            return aIsComm - bIsComm;',
'        });',
'        // Set styles explicitly per series',
'        data.series.forEach(function(s) {',
'            var colors = {',
'                ''none'':        {fill:''rgba(136,135,128,0.12)'',stroke:''#888780''},',
'                ''centralized'': {fill:''rgba(55,138,221,0.12)'', stroke:''#378ADD''},',
'                ''proximity'':   {fill:''rgba(29,158,117,0.12)'', stroke:''#1D9E75''},',
'                ''scout'':       {fill:''rgba(239,159,39,0.12)'', stroke:''#EF9F27''}',
'            };',
'            var baseName = s.name.replace(''_comm'','''');',
'            var c = colors[baseName] || {fill:''rgba(180,180,180,0.12)'',stroke:''#B4B2A9''};',
'            if (s.name.endsWith(''_comm'')) {',
'                s.style = {',
'                    fill:            ''rgba(0,0,0,0)'',',
'                    stroke:          c.stroke,',
'                    strokeWidth:     2,',
'                    strokeDasharray: ''6 3''',
'                };',
'            } else {',
'                s.style = {',
'                    fill:        c.fill,',
'                    stroke:      c.stroke,',
'                    strokeWidth: 2',
'                };',
'            }',
'        });',
'        return data;',
'    };',
'    return options;',
'}'))
);
wwv_flow_imp_page.create_jet_chart_series(
 p_id=>wwv_flow_imp.id(126363085583261244)
,p_chart_id=>wwv_flow_imp.id(126495878581745017)
,p_seq=>10
,p_name=>'New_1'
,p_data_source_type=>'SQL'
,p_data_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'WITH base AS (',
'    SELECT',
'        comm_mode,',
'        goals_reached_this_ep,',
'        outcome,',
'        (a0_comm_received + a1_comm_received +',
'         a2_comm_received + a3_comm_received)           AS total_comm,',
'        CASE',
'            WHEN outcome = ''timeout''             THEN ''timeout''',
'            WHEN goals_reached_this_ep = 4       THEN ''full_win''',
'            WHEN goals_reached_this_ep > 0       THEN ''partial_win''',
'            WHEN outcome = ''all_dead''            THEN ''all_dead''',
'            ELSE                                      ''no_goal''',
'        END AS end_status',
'    FROM marl_results mr, experiment e, experiment_files ef',
'    WHERE e.id        = ef.experiment_id',
'      AND mr.filename = ef.filename',
'      AND e.id        = :P9_SELECT_EXPERIMENT',
'      AND goal_mode   = :P9_GOAL_MODE',
'      AND COMM_RADIUS = :P9_RADIUS',
'      AND mode_exec   = ''test''',
'),',
'stats AS (',
'    SELECT',
'        comm_mode,',
'        end_status,',
'        COUNT(*)                                        AS n_episodes,',
'        ROUND(COUNT(*) * 100.0 /',
'            SUM(COUNT(*)) OVER (PARTITION BY comm_mode)',
'        , 1)                                            AS outcome_pct,',
'        ROUND(AVG(total_comm), 1)                       AS avg_comm,',
'        ROUND(AVG(total_comm) * 100.0 /',
'            NULLIF(MAX(AVG(total_comm)) OVER (), 0)',
'        , 1)                                            AS comm_rate_norm',
'    FROM base',
'    GROUP BY comm_mode, end_status',
'),',
'styled AS (',
'    SELECT',
'        s.*,',
'        -- Solid fill colour per mode',
'        CASE comm_mode',
'            WHEN ''none''         THEN ''rgba(136,135,128,0.15)''',
'            WHEN ''centralized''  THEN ''rgba(55,138,221,0.15)''',
'            WHEN ''proximity''    THEN ''rgba(29,158,117,0.15)''',
'            WHEN ''scout''        THEN ''rgba(239,159,39,0.15)''',
'            ELSE                     ''rgba(180,180,180,0.15)''',
'        END                                             AS fill_color,',
'        -- Solid stroke colour per mode',
'        CASE comm_mode',
'            WHEN ''none''         THEN ''#888780''',
'            WHEN ''centralized''  THEN ''#378ADD''',
'            WHEN ''proximity''    THEN ''#1D9E75''',
'            WHEN ''scout''        THEN ''#EF9F27''',
'            ELSE                     ''#B4B2A9''',
'        END                                             AS stroke_color,',
'        -- Dashed stroke colour for comm ring (same colour, dashed)',
'        CASE comm_mode',
'            WHEN ''none''         THEN ''#888780''',
'            WHEN ''centralized''  THEN ''#378ADD''',
'            WHEN ''proximity''    THEN ''#1D9E75''',
'            WHEN ''scout''        THEN ''#EF9F27''',
'            ELSE                     ''#B4B2A9''',
'        END                                             AS comm_stroke_color,',
'        -- Full custom style JSON for performance series',
'        ''{"fill":"'' ||',
'        CASE comm_mode',
'            WHEN ''none''         THEN ''rgba(136,135,128,0.15)''',
'            WHEN ''centralized''  THEN ''rgba(55,138,221,0.15)''',
'            WHEN ''proximity''    THEN ''rgba(29,158,117,0.15)''',
'            WHEN ''scout''        THEN ''rgba(239,159,39,0.15)''',
'            ELSE                     ''rgba(180,180,180,0.15)''',
'        END ||',
'        ''","stroke":"'' ||',
'        CASE comm_mode',
'            WHEN ''none''         THEN ''#888780''',
'            WHEN ''centralized''  THEN ''#378ADD''',
'            WHEN ''proximity''    THEN ''#1D9E75''',
'            WHEN ''scout''        THEN ''#EF9F27''',
'            ELSE                     ''#B4B2A9''',
'        END ||',
'        ''","strokeWidth":2}''                            AS custom_style,',
'        -- Full custom style JSON for comm ring series (dashed, no fill)',
'        ''{"fill":"rgba(0,0,0,0)","stroke":"'' ||',
'        CASE comm_mode',
'            WHEN ''none''         THEN ''#888780''',
'            WHEN ''centralized''  THEN ''#378ADD''',
'            WHEN ''proximity''    THEN ''#1D9E75''',
'            WHEN ''scout''        THEN ''#EF9F27''',
'            ELSE                     ''#B4B2A9''',
'        END ||',
'        ''","strokeWidth":2,"strokeDasharray":"6 3"}''   AS comm_custom_style',
'    FROM stats s',
')',
'',
'',
'-- Comm ring series with dashed style',
'SELECT',
'    comm_mode || ''_comm''                                AS series,',
'    end_status                                          AS label,',
'    comm_rate_norm                                      AS value,',
'    comm_custom_style                                   AS style',
'FROM styled',
'',
'ORDER BY label, series'))
,p_ajax_items_to_submit=>'P9_SELECT_EXPERIMENT,P9_GOAL_MODE,P9_RADIUS'
,p_series_type=>'line'
,p_series_name_column_name=>'SERIES'
,p_items_value_column_name=>'VALUE'
,p_items_label_column_name=>'LABEL'
,p_custom_column_name=>'STYLE'
,p_line_type=>'auto'
,p_items_label_rendered=>false
);
