wwv_flow_imp_page.create_jet_chart_series(
 p_id=>wwv_flow_imp.id(128537534489194509)
,p_chart_id=>wwv_flow_imp.id(128537423909194508)
,p_seq=>10
,p_name=>'New_1'
,p_data_source_type=>'SQL'
,p_data_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'    comm_mode || '' - a'' || agent_num                    AS series,',
'    CASE',
unistr('        WHEN min_dist <= 1 THEN ''01_very_close  (\22641)'''),
'        WHEN min_dist <= 3 THEN ''02_close       (1-3)''',
'        WHEN min_dist <= 6 THEN ''03_medium      (3-6)''',
'        WHEN min_dist <= 9 THEN ''04_far         (6-9)''',
'        ELSE                    ''05_very_far    (9+)''',
'    END                                                 AS label,',
'    COUNT(*)                                            AS value',
'FROM (',
'    SELECT comm_mode, 0 AS agent_num, a0_min_dist AS min_dist',
'    FROM marl_results mr, experiment e, experiment_files ef',
'    WHERE e.id        = ef.experiment_id',
'      AND mr.filename = ef.filename',
'      AND e.id        = :P10_SELECT_EXPERIMENT',
'      AND mode_exec   = ''test''',
'      and comm_mode=''proximity''',
'      AND goal_mode   = :P10_GOAL_MODE',
'      AND comm_radius = :P10_RADIUS',
'      AND a0_min_dist > 0                -- exclude winners',
'',
'    UNION ALL',
'    SELECT comm_mode, 1, a1_min_dist',
'    FROM marl_results mr, experiment e, experiment_files ef',
'    WHERE e.id        = ef.experiment_id',
'      AND mr.filename = ef.filename',
'      AND e.id        = :P10_SELECT_EXPERIMENT',
'      AND mode_exec   = ''test''',
'            and comm_mode=''proximity''',
'      AND goal_mode   = :P10_GOAL_MODE',
'      AND comm_radius = :P10_RADIUS',
'      AND a1_min_dist > 0',
'',
'    UNION ALL',
'    SELECT comm_mode, 2, a2_min_dist',
'    FROM marl_results mr, experiment e, experiment_files ef',
'    WHERE e.id        = ef.experiment_id',
'      AND mr.filename = ef.filename',
'      AND e.id        = :P10_SELECT_EXPERIMENT',
'      AND mode_exec   = ''test''',
'            and comm_mode=''proximity''',
'      AND goal_mode   = :P10_GOAL_MODE',
'      AND comm_radius = :P10_RADIUS',
'      AND a2_min_dist > 0',
'',
'    UNION ALL',
'    SELECT comm_mode, 3, a3_min_dist',
'    FROM marl_results mr, experiment e, experiment_files ef',
'    WHERE e.id        = ef.experiment_id',
'      AND mr.filename = ef.filename',
'      AND e.id        = :P10_SELECT_EXPERIMENT',
'      AND mode_exec   = ''test''',
'            and comm_mode=''proximity''',
'      AND goal_mode   = :P10_GOAL_MODE',
'      AND comm_radius = :P10_RADIUS',
'      AND a3_min_dist > 0',
') agent_data',
'GROUP BY',
'    comm_mode,',
'    agent_num,',
'    CASE',
unistr('        WHEN min_dist <= 1 THEN ''01_very_close  (\22641)'''),
'        WHEN min_dist <= 3 THEN ''02_close       (1-3)''',
'        WHEN min_dist <= 6 THEN ''03_medium      (3-6)''',
'        WHEN min_dist <= 9 THEN ''04_far         (6-9)''',
'        ELSE                    ''05_very_far    (9+)''',
'    END',
'ORDER BY label, series'))
,p_ajax_items_to_submit=>'P10_SELECT_EXPERIMENT,P10_GOAL_MODE,P10_RADIUS'
,p_series_name_column_name=>'SERIES'
,p_items_value_column_name=>'VALUE'
,p_items_label_column_name=>'LABEL'
