wwv_flow_imp_page.create_jet_chart_series(
 p_id=>wwv_flow_imp.id(126881843187029359)
,p_chart_id=>wwv_flow_imp.id(126880166700029353)
,p_seq=>10
,p_name=>'cumulative agent status'
,p_data_source_type=>'SQL'
,p_data_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'WITH base AS (',
'    SELECT',
'        comm_mode,',
'        goal_mode,',
'        steps,',
'        -- Coverage rate per player (comm_received / steps = % of episode with signal)',
'        ROUND(a0_comm_received * 100.0 / NULLIF(steps, 0), 1) AS a0_coverage,',
'        ROUND(a1_comm_received * 100.0 / NULLIF(steps, 0), 1) AS a1_coverage,',
'        ROUND(a2_comm_received * 100.0 / NULLIF(steps, 0), 1) AS a2_coverage,',
'        ROUND(a3_comm_received * 100.0 / NULLIF(steps, 0), 1) AS a3_coverage,',
'        a0_is_scout, a1_is_scout, a2_is_scout, a3_is_scout,',
'        goals_reached_this_ep',
'    FROM marl_results mr, experiment e, experiment_files ef',
'    WHERE e.id        = ef.experiment_id',
'      AND mr.filename = ef.filename',
'      AND e.id        = :P10_SELECT_EXPERIMENT',
'      AND mode_exec   = ''test''',
'      and goal_mode = :P10_GOAL_MODE',
'      and comm_radius=:P10_RADIUS',
'),',
'unpivoted AS (',
'    -- One row per agent per episode',
'    SELECT comm_mode, goal_mode, goals_reached_this_ep,',
'           0 AS agent_id, a0_is_scout AS is_scout, a0_coverage AS coverage',
'    FROM base WHERE a0_is_scout = 0',
'    UNION ALL',
'    SELECT comm_mode, goal_mode, goals_reached_this_ep,',
'           1, a1_is_scout, a1_coverage FROM base WHERE a1_is_scout = 0',
'    UNION ALL',
'    SELECT comm_mode, goal_mode, goals_reached_this_ep,',
'           2, a2_is_scout, a2_coverage FROM base WHERE a2_is_scout = 0',
'    UNION ALL',
'    SELECT comm_mode, goal_mode, goals_reached_this_ep,',
'           3, a3_is_scout, a3_coverage FROM base WHERE a3_is_scout = 0',
')',
'SELECT',
'    comm_mode,',
'    goal_mode,',
'    CASE',
'        WHEN coverage = 0                THEN ''00_no_signal      (0%)''',
'        WHEN coverage <= 10             THEN ''01_very_rare   (1-10%)''',
'        WHEN coverage <= 25             THEN ''02_rare       (11-25%)''',
'        WHEN coverage <= 50             THEN ''03_occasional (26-50%)''',
'        WHEN coverage <= 75             THEN ''04_frequent   (51-75%)''',
'        ELSE                                 ''05_always     (76-100%)''',
'    END                                                 AS coverage_bucket,',
'    COUNT(*)                                            AS n_agent_episodes,',
'    ROUND(COUNT(*) * 100.0 /',
'        SUM(COUNT(*)) OVER (PARTITION BY comm_mode, goal_mode)',
'    , 1)                                                AS pct,',
'    ROUND(AVG(goals_reached_this_ep), 2)                AS avg_goals_in_bucket',
'FROM unpivoted',
'GROUP BY',
'    comm_mode,',
'    goal_mode,',
'    CASE',
'        WHEN coverage = 0                THEN ''00_no_signal      (0%)''',
'        WHEN coverage <= 10             THEN ''01_very_rare   (1-10%)''',
'        WHEN coverage <= 25             THEN ''02_rare       (11-25%)''',
'        WHEN coverage <= 50             THEN ''03_occasional (26-50%)''',
'        WHEN coverage <= 75             THEN ''04_frequent   (51-75%)''',
'        ELSE                                 ''05_always     (76-100%)''',
'    END',
'ORDER BY comm_mode, goal_mode, coverage_bucket'))
,p_max_row_count=>20
,p_ajax_items_to_submit=>'P10_SELECT_EXPERIMENT,P10_GOAL_MODE,P10_RADIUS'
,p_series_name_column_name=>'COVERAGE_BUCKET'
,p_items_value_column_name=>'PCT'
,p_items_label_column_name=>'COMM_MODE'
,p_assigned_to_y2=>'off'
,p_items_label_rendered=>true
,p_items_label_position=>'auto'
);
