wwv_flow_imp_page.create_jet_chart_series(
 p_id=>wwv_flow_imp.id(126876457724029339)
,p_chart_id=>wwv_flow_imp.id(126874707467029333)
,p_seq=>10
,p_name=>'death'
,p_data_source_type=>'SQL'
,p_data_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'WITH agent_level AS (',
'    SELECT',
'        comm_mode, goal_mode, steps,',
'        0                                               AS agent_id,',
'        a0_in_hole                                      AS died,',
'        a0_is_scout                                     AS is_scout,',
'        ROUND(a0_comm_received * 100.0 /',
'              NULLIF(steps, 0), 1)                      AS coverage_pct',
'    FROM marl_results mr, experiment e, experiment_files ef',
'    WHERE e.id = ef.experiment_id AND mr.filename = ef.filename',
'      AND e.id = :P10_SELECT_EXPERIMENT',
'             and comm_radius=:P10_RADIUS',
'      AND mode_exec = ''test'' AND goal_mode = :P10_GOAL_MODE',
'    UNION ALL',
'    SELECT comm_mode, goal_mode, steps, 1, a1_in_hole, a1_is_scout,',
'           ROUND(a1_comm_received * 100.0 / NULLIF(steps,0), 1)',
'    FROM marl_results mr, experiment e, experiment_files ef',
'    WHERE e.id = ef.experiment_id AND mr.filename = ef.filename',
'      AND e.id = :P10_SELECT_EXPERIMENT',
'             and comm_radius=:P10_RADIUS',
'      AND mode_exec = ''test'' AND goal_mode = :P10_GOAL_MODE',
'    UNION ALL',
'    SELECT comm_mode, goal_mode, steps, 2, a2_in_hole, a2_is_scout,',
'           ROUND(a2_comm_received * 100.0 / NULLIF(steps,0), 1)',
'    FROM marl_results mr, experiment e, experiment_files ef',
'    WHERE e.id = ef.experiment_id AND mr.filename = ef.filename',
'      AND e.id = :P10_SELECT_EXPERIMENT',
'             and comm_radius=:P10_RADIUS',
'      AND mode_exec = ''test'' AND goal_mode = :P10_GOAL_MODE',
'    UNION ALL',
'    SELECT comm_mode, goal_mode, steps, 3, a3_in_hole, a3_is_scout,',
'           ROUND(a3_comm_received * 100.0 / NULLIF(steps,0), 1)',
'    FROM marl_results mr, experiment e, experiment_files ef',
'    WHERE e.id = ef.experiment_id AND mr.filename = ef.filename',
'      AND e.id = :P10_SELECT_EXPERIMENT',
'             and comm_radius=:P10_RADIUS',
'      AND mode_exec = ''test'' AND goal_mode = :P10_GOAL_MODE',
'),',
'dead_agents AS (',
'    SELECT',
'        comm_mode,',
'        CASE',
'            WHEN coverage_pct = 0    THEN ''00_no_signal      (0%)''',
'            WHEN coverage_pct <= 10  THEN ''01_very_rare   (1-10%)''',
'            WHEN coverage_pct <= 25  THEN ''02_rare       (11-25%)''',
'            WHEN coverage_pct <= 50  THEN ''03_occasional (26-50%)''',
'            WHEN coverage_pct <= 75  THEN ''04_frequent   (51-75%)''',
'            ELSE                          ''05_always     (76-100%)''',
'        END                                             AS bucket,',
'        COUNT(*)                                        AS n_dead',
'    FROM agent_level',
'    WHERE died     = 1',
'      AND is_scout = 0',
'    GROUP BY',
'        comm_mode,',
'        CASE',
'            WHEN coverage_pct = 0    THEN ''00_no_signal      (0%)''',
'            WHEN coverage_pct <= 10  THEN ''01_very_rare   (1-10%)''',
'            WHEN coverage_pct <= 25  THEN ''02_rare       (11-25%)''',
'            WHEN coverage_pct <= 50  THEN ''03_occasional (26-50%)''',
'            WHEN coverage_pct <= 75  THEN ''04_frequent   (51-75%)''',
'            ELSE                          ''05_always     (76-100%)''',
'        END',
'),',
'-- All comm_modes present in the experiment',
'all_modes AS (',
'    SELECT DISTINCT comm_mode',
'    FROM marl_results mr, experiment e, experiment_files ef',
'    WHERE e.id = ef.experiment_id AND mr.filename = ef.filename',
'      AND e.id = :P10_SELECT_EXPERIMENT',
'      AND mode_exec = ''test'' AND goal_mode = :P10_GOAL_MODE',
'      AND comm_radius=:P10_RADIUS',
'),',
unistr('-- All buckets \2014 fixed list'),
'all_buckets AS (',
'    SELECT ''00_no_signal      (0%)''  AS bucket FROM dual UNION ALL',
'    SELECT ''01_very_rare   (1-10%)''            FROM dual UNION ALL',
'    SELECT ''02_rare       (11-25%)''            FROM dual UNION ALL',
'    SELECT ''03_occasional (26-50%)''            FROM dual UNION ALL',
'    SELECT ''04_frequent   (51-75%)''            FROM dual UNION ALL',
'    SELECT ''05_always     (76-100%)''           FROM dual',
'),',
unistr('-- Cross join modes \00D7 buckets to get all combinations'),
'all_combinations AS (',
'    SELECT m.comm_mode, b.bucket',
'    FROM all_modes m',
'    CROSS JOIN all_buckets b',
'),',
unistr('-- Left join actual death counts \2014 NULL becomes 0'),
'joined AS (',
'    SELECT',
'        ac.comm_mode,',
'        ac.bucket,',
'        NVL(d.n_dead, 0)                               AS n_dead',
'    FROM all_combinations ac',
'    LEFT JOIN dead_agents d',
'      ON  ac.comm_mode = d.comm_mode',
'      AND ac.bucket    = d.bucket',
'),',
'-- Compute total per mode for percentage',
'with_total AS (',
'    SELECT',
'        comm_mode,',
'        bucket,',
'        n_dead,',
'        SUM(n_dead) OVER (PARTITION BY comm_mode)       AS total_dead',
'    FROM joined',
')',
'SELECT',
'    comm_mode                                           AS series,',
'    bucket                                              AS label,',
'    n_dead,',
'    total_dead,',
unistr('    -- 0 deaths \2192 0% (not NULL)'),
'    ROUND(CASE WHEN total_dead = 0 THEN 0',
'               ELSE n_dead * 100.0 / total_dead',
'          END, 1)                                       AS value',
'FROM with_total',
'ORDER BY label, series'))
,p_max_row_count=>1000
,p_ajax_items_to_submit=>'P10_GOAL_MODE,P10_SELECT_EXPERIMENT,P10_RADIUS'
,p_series_name_column_name=>'LABEL'
,p_items_value_column_name=>'VALUE'
,p_items_label_column_name=>'SERIES'
,p_assigned_to_y2=>'off'
,p_items_label_rendered=>false
);
