wwv_flow_imp_page.create_jet_chart_series(
 p_id=>wwv_flow_imp.id(126873143311029326)
,p_chart_id=>wwv_flow_imp.id(126871478348029318)
,p_seq=>10
,p_name=>'New_1'
,p_data_source_type=>'SQL'
,p_data_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'    comm_mode                                           AS series,',
'    CASE',
'        WHEN LEAST(a0_min_dist, a1_min_dist,',
'                   a2_min_dist, a3_min_dist) = 0  THEN ''00_on_goal     (=0)''',
'        WHEN LEAST(a0_min_dist, a1_min_dist,',
unistr('                   a2_min_dist, a3_min_dist) <= 1 THEN ''01_very_close  (\22641)'''),
'        WHEN LEAST(a0_min_dist, a1_min_dist,',
'                   a2_min_dist, a3_min_dist) <= 3 THEN ''02_close       (1-3)''',
'        WHEN LEAST(a0_min_dist, a1_min_dist,',
'                   a2_min_dist, a3_min_dist) <= 6 THEN ''03_medium      (3-6)''',
'        WHEN LEAST(a0_min_dist, a1_min_dist,',
'                   a2_min_dist, a3_min_dist) <= 9 THEN ''04_far         (6-9)''',
'        ELSE                                            ''05_very_far    (9+)''',
'    END                                                 AS label,',
'    COUNT(*)                                            AS value',
'FROM marl_results mr, experiment e, experiment_files ef',
'WHERE e.id        = ef.experiment_id',
'  AND mr.filename = ef.filename',
'  AND e.id        = :P10_SELECT_EXPERIMENT',
'  AND mode_exec   = ''test''',
'  AND goal_mode   = :P10_GOAL_MODE',
'  AND comm_radius   = :P10_RADIUS',
'  AND LEAST(a0_min_dist, a1_min_dist,',
'            a2_min_dist, a3_min_dist) > 0',
'GROUP BY',
'    comm_mode,',
'    CASE',
'        WHEN LEAST(a0_min_dist, a1_min_dist,',
'                   a2_min_dist, a3_min_dist) = 0  THEN ''00_on_goal     (=0)''',
'        WHEN LEAST(a0_min_dist, a1_min_dist,',
unistr('                   a2_min_dist, a3_min_dist) <= 1 THEN ''01_very_close  (\22641)'''),
'        WHEN LEAST(a0_min_dist, a1_min_dist,',
'                   a2_min_dist, a3_min_dist) <= 3 THEN ''02_close       (1-3)''',
'        WHEN LEAST(a0_min_dist, a1_min_dist,',
'                   a2_min_dist, a3_min_dist) <= 6 THEN ''03_medium      (3-6)''',
'        WHEN LEAST(a0_min_dist, a1_min_dist,',
'                   a2_min_dist, a3_min_dist) <= 9 THEN ''04_far         (6-9)''',
'        ELSE                                            ''05_very_far    (9+)''',
'    END',
'ORDER BY label, series'))
,p_ajax_items_to_submit=>'P10_SELECT_EXPERIMENT,P10_GOAL_MODE,P10_RADIUS'
,p_series_name_column_name=>'SERIES'
,p_items_value_column_name=>'VALUE'
,p_items_label_column_name=>'LABEL'
,p_assigned_to_y2=>'off'
,p_items_label_rendered=>true
,p_items_label_position=>'auto'
);
