,p_seq=>10
,p_name=>'cumulative agent status'
,p_data_source_type=>'SQL'
,p_data_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT comm_mode, mr.filename,''wins''      AS category,',
'    SUM(a0_win + a1_win + a2_win + a3_win)              AS value',
'FROM marl_results mr, experiment e, experiment_files ef',
'WHERE e.id = ef.experiment_id AND mr.filename = ef.filename',
'  AND e.id = :P11_SELECT_EXPERIMENT and goal_mode=:P11_MODE AND mode_exec = ''test''',
'    and COMM_RADIUS = :P11_RADIUS',
'      and comm_mode=:P11_COMM_MODE',
'GROUP BY comm_mode,mr.filename',
'',
'UNION ALL',
'',
'SELECT comm_mode,  mr.filename,''survivors'' AS category,',
'    SUM(GREATEST(',
'        agents_alive_end - (a0_win + a1_win + a2_win + a3_win), 0))',
'FROM marl_results mr, experiment e, experiment_files ef',
'WHERE e.id = ef.experiment_id AND mr.filename = ef.filename',
'  AND e.id = :P11_SELECT_EXPERIMENT and goal_mode=:P11_MODE AND mode_exec = ''test''',
'    and COMM_RADIUS = :P11_RADIUS',
'          and comm_mode=:P11_COMM_MODE',
'GROUP BY comm_mode,mr.filename',
'',
'UNION ALL',
'',
'SELECT comm_mode,  mr.filename,''deaths''    AS category,',
'    SUM(a0_in_hole + a1_in_hole + a2_in_hole + a3_in_hole)',
'FROM marl_results mr, experiment e, experiment_files ef',
'WHERE e.id = ef.experiment_id AND mr.filename = ef.filename',
'  AND e.id = :P11_SELECT_EXPERIMENT  and goal_mode=:P11_MODE AND mode_exec = ''test''',
'    and COMM_RADIUS = :P11_RADIUS',
'          and comm_mode=:P11_COMM_MODE',
'GROUP BY comm_mode,mr.filename',
'',
'ORDER BY comm_mode',
''))
