'    COUNT(*)                                            AS n_episodes,',
'    ROUND(COUNT(*) * 100.0 /',
'        SUM(COUNT(*)) OVER (PARTITION BY comm_mode)',
'    , 1)                                                AS pct_of_episodes,',
'    ROUND(AVG(total_reward), 2)                         AS avg_reward,',
'    ROUND(MIN(total_reward), 2)                         AS min_reward,',
'    ROUND(MAX(total_reward), 2)                         AS max_reward,',
'    ROUND(STDDEV(total_reward), 2)                      AS std_reward',
'FROM marl_results mr, experiment e, experiment_files ef',
'WHERE e.id        = ef.experiment_id',
'  AND mr.filename = ef.filename',
'  AND e.id        = :P11_SELECT_EXPERIMENT',
'  AND mode_exec   = ''test''',
'  and goal_mode = :P11_MODE ',
'    and COMM_RADIUS = :P11_RADIUS',
'                  and comm_mode=:P11_COMM_MODE',
'GROUP BY comm_mode, mr.filename,outcome',
'ORDER BY comm_mode'))
,p_max_row_count=>1000
,p_ajax_items_to_submit=>'P11_MODE,P11_SELECT_EXPERIMENT,P11_RADIUS,P11_COMM_MODE'
,p_series_name_column_name=>'FILENAME'
,p_items_value_column_name=>'AVG_REWARD'
,p_items_label_column_name=>'OUTCOME'
,p_assigned_to_y2=>'off'
,p_items_label_rendered=>false
);
