wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(254689780053204387)
,p_plug_name=>'Agent analysis'
,p_parent_plug_id=>wwv_flow_imp.id(253609563865623189)
,p_region_template_options=>'#DEFAULT#:t-IRR-region--hideHeader js-addHiddenHeadingRoleDesc'
,p_component_template_options=>'#DEFAULT#'
,p_plug_template=>2100526641005906379
,p_plug_display_sequence=>100
,p_plug_display_point=>'SUB_REGIONS'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'    mr.filename,',
'    comm_mode,',
'    -- Agent 0',
'    SUM(a0_win)                                         AS a0_total_wins,',
'    SUM(a0_in_hole)                                     AS a0_total_deaths,',
'    SUM(a0_alive)                                       AS a0_total_alive_end,',
'    ROUND(AVG(a0_win)     * 100, 1)                     AS a0_win_pct,',
'    ROUND(AVG(a0_in_hole) * 100, 1)                     AS a0_death_pct,',
'    -- Agent 1',
'    SUM(a1_win)                                         AS a1_total_wins,',
'    SUM(a1_in_hole)                                     AS a1_total_deaths,',
'    SUM(a1_alive)                                       AS a1_total_alive_end,',
'    ROUND(AVG(a1_win)     * 100, 1)                     AS a1_win_pct,',
'    ROUND(AVG(a1_in_hole) * 100, 1)                     AS a1_death_pct,',
'    -- Agent 2',
'    SUM(a2_win)                                         AS a2_total_wins,',
'    SUM(a2_in_hole)                                     AS a2_total_deaths,',
'    SUM(a2_alive)                                       AS a2_total_alive_end,',
'    ROUND(AVG(a2_win)     * 100, 1)                     AS a2_win_pct,',
'    ROUND(AVG(a2_in_hole) * 100, 1)                     AS a2_death_pct,',
'    -- Agent 3',
'    SUM(a3_win)                                         AS a3_total_wins,',
'    SUM(a3_in_hole)                                     AS a3_total_deaths,',
'    SUM(a3_alive)                                       AS a3_total_alive_end,',
'    ROUND(AVG(a3_win)     * 100, 1)                     AS a3_win_pct,',
'    ROUND(AVG(a3_in_hole) * 100, 1)                     AS a3_death_pct',
'FROM marl_results mr, experiment e, experiment_files ef',
'WHERE e.id        = ef.experiment_id',
'  AND mr.filename = ef.filename',
'  AND e.id        = :P11_SELECT_EXPERIMENT',
'  and goal_mode=:P11_MODE',
'  AND mode_exec   = ''test''',
'    and COMM_RADIUS = :P11_RADIUS',
'                  and comm_mode=:P11_COMM_MODE',
'GROUP BY comm_mode,mr.filename',
