wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(254736273660808468)
,p_plug_name=>'Scout analysis'
,p_parent_plug_id=>wwv_flow_imp.id(253609563865623189)
,p_region_template_options=>'#DEFAULT#:t-IRR-region--hideHeader js-addHiddenHeadingRoleDesc'
,p_component_template_options=>'#DEFAULT#'
,p_plug_template=>2100526641005906379
,p_plug_display_sequence=>110
,p_plug_display_point=>'SUB_REGIONS'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'mr.filename,',
'    comm_mode,',
'    -- Player agents',
'    ROUND(AVG(CASE WHEN a0_is_scout = 0 THEN a0_win END) * 100, 1)  AS a0_win_pct,',
'    ROUND(AVG(CASE WHEN a1_is_scout = 0 THEN a1_win END) * 100, 1)  AS a1_win_pct,',
'    ROUND(AVG(CASE WHEN a2_is_scout = 0 THEN a2_win END) * 100, 1)  AS a2_win_pct,',
'    -- Scout agent',
'    ROUND(AVG(CASE WHEN a3_is_scout = 1 THEN a3_win END) * 100, 1)  AS scout_win_pct,',
'    -- Averages for comparison',
'    ROUND(AVG(',
'        CASE WHEN a0_is_scout = 0 THEN a0_win END +',
'        CASE WHEN a1_is_scout = 0 THEN a1_win END +',
'        CASE WHEN a2_is_scout = 0 THEN a2_win END',
'    ) / 3.0 * 100, 1)                                               AS avg_player_win_pct,',
'    -- Gap: how much less does the scout win vs average player',
'    ROUND((',
'        AVG(',
'            CASE WHEN a0_is_scout = 0 THEN a0_win END +',
'            CASE WHEN a1_is_scout = 0 THEN a1_win END +',
'            CASE WHEN a2_is_scout = 0 THEN a2_win END',
'        ) / 3.0 -',
'        AVG(CASE WHEN a3_is_scout = 1 THEN a3_win END)',
'    ) * 100, 1)                                                      AS player_scout_gap_pct',
'FROM marl_results mr, experiment e, experiment_files ef',
'WHERE e.id        = ef.experiment_id',
'  AND mr.filename = ef.filename',
'  AND e.id        = :P11_SELECT_EXPERIMENT',
'  AND mode_exec   = ''test''',
'  and goal_mode = :P11_MODE',
'    and COMM_RADIUS = :P11_RADIUS',
'                  and comm_mode=:P11_COMM_MODE',
'GROUP BY comm_mode,mr.filename',
''))
,p_plug_source_type=>'NATIVE_IG'
,p_ajax_items_to_submit=>'P11_SELECT_EXPERIMENT,P11_MODE,P11_RADIUS,P11_COMM_MODE'
,p_prn_units=>'INCHES'
,p_prn_paper_size=>'LETTER'
,p_prn_width=>11
,p_prn_height=>8.5
,p_prn_orientation=>'HORIZONTAL'
,p_prn_page_header_font_color=>'#000000'
,p_prn_page_header_font_family=>'Helvetica'
,p_prn_page_header_font_weight=>'normal'
,p_prn_page_header_font_size=>'12'
,p_prn_page_footer_font_color=>'#000000'
