wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(254759365702845846)
,p_plug_name=>'Scout reaching the last'
,p_parent_plug_id=>wwv_flow_imp.id(253609563865623189)
,p_region_template_options=>'#DEFAULT#:t-IRR-region--hideHeader js-addHiddenHeadingRoleDesc'
,p_component_template_options=>'#DEFAULT#'
,p_plug_template=>2100526641005906379
,p_plug_display_sequence=>120
,p_plug_new_grid_row=>false
,p_plug_display_point=>'SUB_REGIONS'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'WITH goal_arrivals AS (',
'    SELECT',
'       mr.filename,',
'        mr.comm_mode,',
'        mr.episode,',
'        -- Scout arrival step',
'        CASE WHEN a3_is_scout = 1 AND a3_win = 1 AND a3_steps_to_goal > 0',
'             THEN a3_steps_to_goal END                               AS scout_steps,',
unistr('        -- Player steps \2014 NULL when agent did not win'),
'        CASE WHEN a0_is_scout = 0 AND a0_win = 1 AND a0_steps_to_goal > 0',
'             THEN a0_steps_to_goal END                               AS p0_steps,',
'        CASE WHEN a1_is_scout = 0 AND a1_win = 1 AND a1_steps_to_goal > 0',
'             THEN a1_steps_to_goal END                               AS p1_steps,',
'        CASE WHEN a2_is_scout = 0 AND a2_win = 1 AND a2_steps_to_goal > 0',
'             THEN a2_steps_to_goal END                               AS p2_steps,',
'        -- Number of players who won',
'        (NVL2(CASE WHEN a0_is_scout=0 AND a0_win=1 AND a0_steps_to_goal>0',
'                   THEN 1 END, 1, 0) +',
'         NVL2(CASE WHEN a1_is_scout=0 AND a1_win=1 AND a1_steps_to_goal>0',
'                   THEN 1 END, 1, 0) +',
'         NVL2(CASE WHEN a2_is_scout=0 AND a2_win=1 AND a2_steps_to_goal>0',
'                   THEN 1 END, 1, 0))                                AS n_players_won',
'    FROM marl_results mr, experiment e, experiment_files ef',
'    WHERE e.id        = ef.experiment_id',
'      AND mr.filename = ef.filename',
'      AND e.id        = :P11_SELECT_EXPERIMENT',
'      AND mode_exec   = ''test''',
'      AND goal_mode = :P11_MODE',
'        and COMM_RADIUS = :P11_RADIUS',
'                      and comm_mode=:P11_COMM_MODE',
'      AND a3_win      = 1',
'      AND a3_is_scout = 1',
'),',
'with_player_stats AS (',
'    SELECT',
'    filename,',
'        comm_mode,',
'        episode,',
'        scout_steps,',
'        n_players_won,',
'        p0_steps,',
'        p1_steps,',
'        p2_steps,',
'        -- First player arrival: MIN ignoring NULLs',
'        -- Oracle MIN() over values ignores NULLs correctly',
'        LEAST(',
'            NVL(p0_steps, NVL(p1_steps, NVL(p2_steps, NULL))),',
'            NVL(p1_steps, NVL(p0_steps, NVL(p2_steps, NULL))),',
'            NVL(p2_steps, NVL(p0_steps, NVL(p1_steps, NULL)))',
'        )                                                            AS first_player_steps,',
'        -- Last player arrival: GREATEST ignoring NULLs',
'        GREATEST(',
'            NVL(p0_steps, 0),',
'            NVL(p1_steps, 0),',
'            NVL(p2_steps, 0)',
'        )                                                            AS last_player_steps',
'    FROM goal_arrivals',
unistr('    WHERE n_players_won > 0   -- \2190 exclude episodes where NO player won'),
')',
'SELECT',
'    filename,',
'    comm_mode,',
'    COUNT(*)                                                         AS scout_win_with_player_episodes,',
'    -- Scout timing',
'    ROUND(AVG(scout_steps), 1)                                       AS avg_scout_steps,',
'    -- First and last player',
'    ROUND(AVG(first_player_steps), 1)                                AS avg_first_player_steps,',
'    ROUND(AVG(last_player_steps), 1)                                 AS avg_last_player_steps,',
'    -- Arrival order',
'    SUM(CASE WHEN scout_steps > last_player_steps',
'             THEN 1 ELSE 0 END)                                      AS scout_arrived_last,',
'    ROUND(SUM(CASE WHEN scout_steps > last_player_steps',
'                   THEN 1 ELSE 0 END) * 100.0 / COUNT(*)',
'    , 1)                                                             AS scout_last_pct,',
'    SUM(CASE WHEN scout_steps < first_player_steps',
'             THEN 1 ELSE 0 END)                                      AS scout_arrived_first,',
'    ROUND(SUM(CASE WHEN scout_steps < first_player_steps',
'                   THEN 1 ELSE 0 END) * 100.0 / COUNT(*)',
'    , 1)                                                             AS scout_first_pct,',
'    SUM(CASE WHEN scout_steps BETWEEN first_player_steps',
'                                  AND last_player_steps',
'             THEN 1 ELSE 0 END)                                      AS scout_arrived_mid,',
'    ROUND(SUM(CASE WHEN scout_steps BETWEEN first_player_steps',
'                                        AND last_player_steps',
'                   THEN 1 ELSE 0 END) * 100.0 / COUNT(*)',
'    , 1)                                                             AS scout_mid_pct,',
'    -- How many steps after last player did the scout arrive',
'    ROUND(AVG(',
'        CASE WHEN scout_steps > last_player_steps',
'             THEN scout_steps - last_player_steps END',
'    ), 1)                                                            AS avg_delay_after_last_player',
'FROM with_player_stats',
'GROUP BY comm_mode,filename',
''))
,p_plug_source_type=>'NATIVE_IG'
,p_ajax_items_to_submit=>'P11_SELECT_EXPERIMENT,P11_MODE,P11_RADIUS,P11_COMM_MODE'
,p_prn_units=>'INCHES'
,p_prn_paper_size=>'LETTER'
,p_prn_width=>11
,p_prn_height=>8.5
,p_prn_orientation=>'HORIZONTAL'
,p_prn_page_header_font_color=>'#000000'
,p_prn_page_header_font_family=>'Helvetica'
,p_prn_page_header_font_weight=>'normal'
,p_prn_page_header_font_size=>'12'
,p_prn_page_footer_font_color=>'#000000'
,p_prn_page_footer_font_family=>'Helvetica'
,p_prn_page_footer_font_weight=>'normal'
,p_prn_page_footer_font_size=>'12'
,p_prn_header_bg_color=>'#EEEEEE'
,p_prn_header_font_color=>'#000000'
,p_prn_header_font_family=>'Helvetica'
,p_prn_header_font_weight=>'bold'
,p_prn_header_font_size=>'10'
,p_prn_body_bg_color=>'#FFFFFF'
,p_prn_body_font_color=>'#000000'
,p_prn_body_font_family=>'Helvetica'
,p_prn_body_font_weight=>'normal'
,p_prn_body_font_size=>'10'
,p_prn_border_width=>.5
,p_prn_page_header_alignment=>'CENTER'
,p_prn_page_footer_alignment=>'CENTER'
,p_prn_border_color=>'#666666'
,p_ai_enabled=>false
);
